import { createPublicClient, http } from 'viem';
import { mainnet } from 'viem/chains';

const client = createPublicClient({ chain: mainnet, transport: http() });

async function awaitFinality(txHash: `0x${string}`) {
  const receipt = await client.waitForTransactionReceipt({ hash: txHash });

  while (true) {
    const finalized = await client.getBlock({ blockTag: 'finalized' });
    if (receipt.blockNumber <= finalized.number) {
      console.log('Tx finalized at block', receipt.blockNumber);
      return receipt;
    }
    await new Promise(r => setTimeout(r, 12_000)); // 1 slot
  }
}

import { ethers } from 'ethers';

// Deposit ERC-20 from Ethereum -> Polygon PoS via RootChainManager
const ROOT_CHAIN_MANAGER = '0xA0c68C638235ee32657e8f720a23ceC1bFc77C77';
const ERC20_PREDICATE  = '0x40ec5B33f54e0E8A33A975908C5BA1c14e5BbbDf';

const abi = ['function depositFor(address user, address rootToken, bytes calldata depositData) external'];

async function depositToPolygon(signer: ethers.Signer, tokenAddress: string, amount: bigint) {
  const token = new ethers.Contract(tokenAddress, ['function approve(address,uint256)'], signer);
  await (await token.approve(ERC20_PREDICATE, amount)).wait();

  const manager = new ethers.Contract(ROOT_CHAIN_MANAGER, abi, signer);
  const depositData = ethers.AbiCoder.defaultAbiCoder().encode(['uint256'], [amount]);
  const tx = await manager.depositFor(await signer.getAddress(), tokenAddress, depositData);
  await tx.wait();
  console.log('Deposit tx:', tx.hash, '— await checkpoint on Polygon PoS (~5-10 min)');
}

