// On-chain SVG metadata with ERC-721 (OpenZeppelin)
function tokenURI(uint256 tokenId) public view override returns (string memory) {
    string memory svg = string(abi.encodePacked(
        '<svg xmlns="http://www.w3.org/2000/svg"><text>',
        Strings.toString(tokenId),
        '</text></svg>'
    ));
    string memory json = Base64.encode(bytes(string(abi.encodePacked(
        '{"name":"Token #', Strings.toString(tokenId),
        '","image":"data:image/svg+xml;base64,', Base64.encode(bytes(svg)), '"}'
    ))));
    return string(abi.encodePacked('data:application/json;base64,', json));
}

import { ethers } from 'ethers';
import { AggregatorV3Interface__factory } from './typechain';

// Chainlink price feed with staleness guard
async function getSafePrice(feedAddress: string, provider: ethers.Provider): Promise<bigint> {
  const feed = AggregatorV3Interface__factory.connect(feedAddress, provider);
  const { answer, updatedAt } = await feed.latestRoundData();
  const stalenessThreshold = 3600n; // 1 hour in seconds
  const now = BigInt(Math.floor(Date.now() / 1000));
  if (now - updatedAt > stalenessThreshold) throw new Error('Stale oracle price');
  return answer;
}

